{
  "files": [
    {
      "path": "package.json",
      "content": "{
  "name": "project-management",
  "version": "1.0.0",
  "description": "A simple project management API",
  "main": "src/app.js",
  "scripts": {
    "start": "node src/server.js",
    "test": "node --test tests/oracle.test.js"
  },
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "supertest": "^6.3.3"
  }
}
"
    },
    {
      "path": "src/app.js",
      "content": "const express = require('express');
const app = express();

app.use(express.json());

// Health endpoint
app.get('/health', (req, res) => {
  res.status(200).json({ ok: true });
});

// Import project routes
const projectRoutes = require('./modules/projects/routes');
app.use('/projects', projectRoutes);

module.exports = app;
"
    },
    {
      "path": "src/server.js",
      "content": "const app = require('./app');
const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
"
    }
  ],
  "notes": "Added server.js and updated package.json to include supertest in devDependencies."
}
